import React from "react";
import { Box, Text } from "@chakra-ui/react";
import { FaCheck } from "react-icons/fa";

const SingleList = () => {
  const list = [
    "Build enterprise level Node applications and deploy to AWS",
    "Lead NodeJS projects with strong architecture decisions",
    "Build a NASA launch system using SpaceX API",
    "Create full MERN stack apps and deploy to production",
    "Become a top 10% Node Developer",
    "Master backend ecosystem from scratch",
    "Build secure & scalable applications",
    "Develop REST & GraphQL APIs",
    "Work with databases (SQL, MongoDB)",
    "Learn CI/CD, monitoring & deployment",
    "Apply security best practices",
  ];

  return (
    <Box
      bg="white"
      border="1px solid #e5e7eb"
      borderRadius="lg"
      p={6}
      maxW="900px"
      mx="auto"
      boxShadow="sm"
    >
      {/* TITLE */}
      <Text fontSize="xl" fontWeight="bold" mb={4}>
        What you'll learn
      </Text>

      {/* LIST */}
      <Box
        display="grid"
        gridTemplateColumns={{ base: "1fr", md: "1fr 1fr" }}
        gap={4}
      >
        {list.map((item, index) => (
          <Box key={index} display="flex" alignItems="flex-start" gap={3}>
            <FaCheck
              style={{
                color: "#A435F0",
                marginTop: "4px",
                fontSize: "14px",
              }}
            />
            <Text fontSize="sm" color="gray.700" lineHeight="1.5">
              {item}
            </Text>
          </Box>
        ))}
      </Box>
    </Box>
  );
};

export default SingleList;
